module temp_sensor_comparator (
    input [3:0] temperature,
    input reset,
    output reg no_alert
);
    always @(*) begin
        if (reset) 
            no_alert = 0;
        else 
            no_alert = (temperature > 4'b1010) ? 1 : 0; // 10 degrees Celsius in binary
    end
endmodule
